class Solution:
    def dominantIndex(self, nums):
        best = second = -1
        idx = -1
        for i, v in enumerate(nums):
            if v > best:
                second = best
                best = v
                idx = i
            elif v > second:
                second = v
        return idx if best >= 2 * second else -1

