var dominantIndex = function(nums) {
    let best = -1, second = -1, idx = -1;
    for (let i = 0; i < nums.length; i++) {
        const v = nums[i];
        if (v > best) {
            second = best;
            best = v;
            idx = i;
        } else if (v > second) {
            second = v;
        }
    }
    return best >= 2 * second ? idx : -1;
};
